 function itemSuggestions(state,index,line){if(ui.suggestions!==index)return'';const query=String(line.name||'').trim().toLocaleLowerCase('fr');if(ui.suggestionReady!==index)return`<div class="document-v2-suggestions loading"><span>Recherche…</span></div>`;const rows=(state.data.catalog||[]).filter(x=>x.active!==false&&[x.name,x.reference,x.short_description,x.sales_description].join(' ').toLocaleLowerCase('fr').includes(query)).slice(0,8),exact=rows.some(x=>[x.name,x.reference].some(value=>String(value||'').trim().toLocaleLowerCase('fr')===query));return`<div class="document-v2-suggestions" onmousedown="event.preventDefault()">${rows.map(item=>`<button type="button" onclick="PilozDocumentEditorV2.selectItem(${index},'${item.id}')"><b>${esc(item.name)}</b><small>${esc(item.reference||'Sans référence')} · ${money(item.sale_price)}</small></button>`).join('')}${query&&!exact?`<button type="button" class="create" onclick="PilozDocumentEditorV2.openItemCreator(${index})">Créer l’article ou service « ${esc(line.name)} »</button>`:''}${query?`<button type="button" onclick="PilozDocumentEditorV2.keepOneOff(${index})">Conserver « ${esc(line.name)} » comme ligne ponctuelle</button>`:''}${!rows.length&&!query?'<span>Commencez à saisir une référence ou une désignation.</span>':''}</div>`;}
