 function lineMenu(index){return`<details class="document-v2-line-menu" ${ui.lineMenu===index?'open':''} onclick="event.stopPropagation()"><summary onclick="PilozDocumentEditorV2.toggleLineMenu(${index})">⋮</summary><div>${[['description','Ajouter une description'],['discount','Ajouter une remise'],['reference','Ajouter une référence'],['duplicate','Dupliquer la ligne'],['option','Transformer en option'],['variant','Transformer en variante'],['section','Déplacer vers une section'],['delete','Supprimer']].map(([action,label])=>`<button type="button" onclick="PilozDocumentEditorV2.lineAction(${index},'${action}')">${esc(label)}</button>`).join('')}</div></details>`;}
