 function sidePanel(state,d){const templates=(state.data.templates||[]).filter(x=>x.status==='active'&&(!x.document_type||x.document_type===d.document_type)),stages=(state.data.pipelineStages||[]).filter(x=>x.active!==false),methods=enabledPaymentMethods(state),terms=enabledPaymentTerms(state),methodMatch=value=>String(d.payment_method||'')===String(value.value)||String(d.payment_method||'').toLocaleLowerCase('fr')===String(value.label||'').toLocaleLowerCase('fr'),termMatch=value=>String(d.payment_terms||'')===String(value.value)||String(d.payment_terms||'').toLocaleLowerCase('fr')===String(value.label||'').toLocaleLowerCase('fr');return`<aside class="document-v2-panel"><header><h2>Paramètres</h2><button type="button" onclick="PilozDocumentEditorV2.togglePanel()" aria-label="Replier les paramètres">→</button></header><section><h3>Modèle utilisé</h3><select ${disabled(d)} onchange="PilozDocumentEditorV2.setDraft('template_id',this.value)"><option value="">Modèle par défaut</option>${templates.map(x=>`<option value="${x.id}" ${d.template_id===x.id?'selected':''}>${esc(x.name)}</option>`).join('')}</select></section><section><h3>Langue</h3><label>Langue du document<select ${disabled(d)} onchange="PilozDocumentEditorV2.setDraft('language',this.value)"><option value="fr">Français</option><option value="en" ${d.language==='en'?'selected':''}>English</option></select></label></section><section><h3>Conditions de paiement</h3><label>Délai<select ${disabled(d)} onchange="PilozDocumentEditorV2.setDraft('payment_terms',this.value)">${terms.map(term=>`<option value="${esc(term.value)}" ${termMatch(term)?'selected':''}>${esc(term.label)}</option>`).join('')}</select></label><div class="document-v2-payment-methods">${methods.map(method=>`<label><input ${disabled(d)} type="radio" name="document_payment_method" value="${esc(method.value)}" ${methodMatch(method)?'checked':''} onchange="PilozDocumentEditorV2.setDraft('payment_method',this.value)"><span>${esc(method.label)}</span></label>`).join('')}</div></section><section><h3>Suivi commercial</h3><label>Commercial<select ${disabled(d)} onchange="PilozDocumentEditorV2.setDraft('assigned_user_id',this.value)"><option value="">Non attribué</option>${memberOptions(state,d)}</select></label><label>Pipeline<select ${disabled(d)} onchange="PilozDocumentEditorV2.setDraft('pipeline_stage',this.value)"><option value="">Automatique selon le document</option>${stages.map(stage=>`<option value="${esc(stage.slug)}" ${d.pipeline_stage===stage.slug?'selected':''}>${esc(stage.name)}</option>`).join('')}</select></label></section><section><h3>Devise</h3><label>Devise<input ${disabled(d)} maxlength="3" value="${esc(d.currency||'EUR')}" onchange="PilozDocumentEditorV2.setDraft('currency',this.value.toUpperCase())"></label></section><section><h3>Notes internes</h3><label>Visibles uniquement par votre équipe<textarea ${disabled(d)} onchange="PilozDocumentEditorV2.setDraft('internal_notes',this.value)">${esc(d.internal_notes||'')}</textarea></label></section><section><h3>Options avancées</h3><label>Référence client<input ${disabled(d)} value="${esc(d.client_reference||'')}" onchange="PilozDocumentEditorV2.setDraft('client_reference',this.value)"></label><label>Remise globale (%)<input ${disabled(d)} type="number" min="0" max="100" step="0.01" value="${Number(d.discount_rate)||0}" onchange="PilozDocumentEditorV2.setDraft('discount_rate',this.value,true)"></label></section></aside>`;}
 function moreActions(d){if(!d.id)return'';return`<details class="erp-action-menu document-v2-actions"><summary class="btn btn-o">Plus d’actions</summary><div>${button('Dupliquer','PilozApp.duplicateDocument()','btn-ghost')}${d.document_type==='quote'?button('Marquer envoyé',"PilozApp.setDocumentStatus('sent')",'btn-ghost')+button('Accepter',"PilozApp.setDocumentStatus('accepted')",'btn-ghost')+button('Refuser',"PilozApp.setDocumentStatus('rejected')",'btn-ghost')+button('Convertir en facture',"PilozApp.convertDocument('invoice')",'btn-ghost')+button('Créer une facture d’acompte',"PilozApp.convertDocument('deposit_invoice')",'btn-ghost'):''}${invoiceTypes.has(d.document_type)?button('Enregistrer un paiement','PilozApp.openPaymentForm()','btn-ghost')+button('Relancer','PilozApp.createReminder()','btn-ghost')+button('Créer un avoir',"PilozApp.convertDocument('credit_note')",'btn-ghost'):''}${button('Archiver',"PilozApp.setDocumentStatus('archived')",'btn-ghost')}</div></details>`;}
 function issuerBlock(state){const row=state.data.settings?.[0]||{},address=[row.address_line1||row.address_line_1,row.address_line2||row.address_line_2,row.postal_code,row.city,row.country_code].filter(Boolean).join(', ');return`<section class="document-v2-issuer"><span>Émetteur ou émettrice</span><b>${esc(row.legal_name||'Votre entreprise')}</b>${address?`<small>${esc(address)}</small>`:''}${row.email?`<small>${esc(row.email)}</small>`:''}${row.phone||row.phone_e164?`<small>${esc(row.phone||row.phone_e164)}</small>`:''}${row.siret?`<small>SIRET : ${esc(row.siret)}</small>`:''}${row.subject_to_vat&&row.vat_number?`<small>TVA : ${esc(row.vat_number)}</small>`:''}</section>`;}
 function metadataBlock(d,title){return`<section class="document-v2-meta"><h2>${esc(title)}</h2><label>Numéro<input disabled value="${esc(documentNumber(d))}"></label><label>Date d’émission<input ${disabled(d)} type="date" value="${esc(d.issue_date||'')}" onchange="PilozDocumentEditorV2.setDraft('issue_date',this.value)"></label><label>${d.document_type==='quote'?'Date de validité':'Date d’échéance'}<input ${disabled(d)} type="date" value="${esc(d.document_type==='quote'?d.validity_date||'':d.due_date||'')}" onchange="PilozDocumentEditorV2.setDraft('${d.document_type==='quote'?'validity_date':'due_date'}',this.value)"></label><label>Objet<input ${disabled(d)} value="${esc(d.subject||'')}" placeholder="Objet du document" onchange="PilozDocumentEditorV2.setDraft('subject',this.value)"></label><label>Type de vente<select ${disabled(d)} required onchange="PilozDocumentEditorV2.setDraft('sale_type',this.value)"><option value="goods" ${d.sale_type==='goods'?'selected':''}>Livraison de biens</option><option value="services" ${d.sale_type==='services'?'selected':''}>Prestation de services</option><option value="goods_and_services" ${d.sale_type==='goods_and_services'?'selected':''}>Livraison de biens et prestation de services</option></select></label></section>`;}
 function documentValidation(d){const saleLines=(d.lines||[]).filter(line=>['item','free_item','option','variant'].includes(line.line_type)&&!line.optional);if(!d.client_id)return'Sélectionnez un client.';if(!saleLines.length)return'Ajoutez au moins une ligne.';if(saleLines.some(line=>!String(line.name||'').trim()||Number(line.quantity)<=0))return'Complétez la désignation et la quantité de chaque ligne.';const totals=calc().document(d.lines,d.discount_rate);if(totals.ttc<=0)return'Le montant total doit être supérieur à zéro pour finaliser.';return'';}
