 async function finalizeDocument(confirmed=false){const d=s().draft;if(ui.finalizing||locked(d))return;const error=documentValidation(d);if(error){global.PilozCommercialV2.notify(error,'error');return;}if(invoiceTypes.has(d.document_type)&&!confirmed){askInvoiceFinalization();return;}closeFinalizeModal();ui.finalizing=true;try{const savedId=await app().saveDocument();if(!savedId)throw new Error('Le brouillon n’a pas pu être enregistré. La finalisation est annulée.');const saved=s().draft;if(!saved?.id)throw new Error('Enregistrez d’abord le brouillon.');if(typeof app().finalizeCurrentDocument==='function'){const result=await app().finalizeCurrentDocument();if(!result)throw new Error('La finalisation a échoué. Le brouillon est conservé.');if(global.PilozDocumentViewerV2)global.PilozDocumentViewerV2.open(result.id||saved.id);}else if(invoiceTypes.has(saved.document_type))await app().validateInvoice();else await app().setDocumentStatus('finalized');}catch(error2){global.PilozCommercialV2.notify(error2.message||'La finalisation a échoué. Le brouillon est conservé.','error');}finally{ui.finalizing=false;}}
