 function renderPaymentHistory(state,d){const rows=(state.data.payments||[]).filter(x=>x.document_id===d.id),paid=rows.filter(x=>x.status==='confirmed').reduce((n,x)=>n+Number(x.amount||0),0),remaining=Math.max(0,Number(d.total_incl_tax||calc().document(d.lines,d.discount_rate).ttc)-paid);return`<section class="document-v2-payments"><header><h2>Encaissement</h2><div><b>${money(paid)} encaissé</b><span>${money(remaining)} restant</span>${remaining>0?button('Enregistrer un paiement','PilozApp.openPaymentForm()','btn-p'):''}</div></header>${rows.length?`<ul>${rows.map(x=>`<li><span>${global.PilozCommercialV2.date(x.paid_at)} · ${esc(x.payment_method||'')}</span><b>${money(x.amount)}</b>${x.status!=='confirmed'?'<small>Annulé</small>':''}</li>`).join('')}</ul>`:'<p>Aucun paiement enregistré.</p>'}</section>`;}
